    await page.goto('https://x.com/i/flow/login', { waitUntil: 'networkidle2', timeout: 30000 })

    // Enter username
    await page.waitForSelector('input[autocomplete="username"]', { timeout: 15000 })
    await page.type('input[autocomplete="username"]', username, { delay: 50 })
    await page.keyboard.press('Enter')

    // Enter password
    await page.waitForSelector('input[type="password"]', { timeout: 15000 })
    await page.type('input[type="password"]', password, { delay: 50 })
    await page.keyboard.press('Enter')

    // Wait for home timeline
    await page.waitForSelector('article[data-testid="tweet"]', { timeout: 30000 })

    // Scrape first 5 tweets
    const tweets = await page.$$eval(
      'article[data-testid="tweet"]',
      (els) => els.slice(0, 5).map((el) => {
        const text = el.querySelector('[data-testid="tweetText"]')?.innerText || ''
        const author = el.querySelector('[data-testid="User-Name"]')?.innerText?.split('\n')[0] || 'Unknown'
        return `${author}: ${text}`
      })
    )

    if (tweets.length === 0) {
      return 'Logged in successfully but could not find any tweets on the timeline.'
    }

    return 'Here are the latest tweets from your timeline:\n\n' + tweets.map((t, i) => `${i + 1}. ${t}`).join('\n\n')
  } catch (err) {
    return `Failed to fetch Twitter timeline: ${err.message}`
  } finally {
    if (browser) await browser.close()
  }
}

