      + `/onboard — Set up platform accounts (Twitter, etc.)\n`
      + `/clear — Reset our conversation history.`,
  })
  console.log(`[${jid}] /help`)
  continue
}

// /clear command — reset conversation history
if (userText.toLowerCase().startsWith('/clear')) {
  chatHistories.delete(jid)
  onboardingSessions.delete(jid)
  await sock.sendMessage(jid, { text: 'Conversation cleared.' })
  console.log(`[${jid}] Conversation history cleared`)
  continue
}

// /onboard command — start account setup
if (userText.toLowerCase().startsWith('/onboard')) {
  const platforms = getPlatforms()
  const keys = Object.keys(platforms)
  let list = 'Add accounts:\n\n'
  keys.forEach((key, i) => {
    const existing = getAccount(key)
    const status = existing ? ' (configured)' : ''
    list += `${i + 1}. ${platforms[key].label}${status}\n`
  })
  list += '\n(More platforms coming soon)\n\nReply with the platform name or number to set it up. Send /cancel to exit.'

  onboardingSessions.set(jid, { step: 'choose_platform' })
  await sock.sendMessage(jid, { text: list })
  console.log(`[${jid}] /onboard`)
  continue
}

// /cancel command — exit onboarding
if (userText.toLowerCase().startsWith('/cancel') && onboardingSessions.has(jid)) {
  onboardingSessions.delete(jid)
  await sock.sendMessage(jid, { text: 'Onboarding cancelled.' })
  continue
}

// Handle active onboarding session
if (onboardingSessions.has(jid)) {
  const session = onboardingSessions.get(jid)
  const platforms = getPlatforms()
  const keys = Object.keys(platforms)

  if (session.step === 'choose_platform') {
    const input = userText.trim().toLowerCase()
    let chosenKey = null

    // Match by number or name
    const num = parseInt(input)
    if (num >= 1 && num <= keys.length) {
      chosenKey = keys[num - 1]
    } else if (keys.includes(input)) {
      chosenKey = input
    }

    if (!chosenKey) {
      await sock.sendMessage(jid, { text: `I didn't recognize that platform. Reply with a number (1-${keys.length}) or platform name. Send /cancel to exit.` })
      continue
    }

    const platform = platforms[chosenKey]
    session.platform = chosenKey
    session.data = {}
    session.fields = [...platform.fields]
    session.currentField = 0
    session.step = 'collect_field'

    await sock.sendMessage(jid, { text: `Setting up ${platform.label}.\n\nEnter your ${platform.fields[0]}:` })
    continue
  }

  if (session.step === 'collect_field') {
    const fieldName = session.fields[session.currentField]
    session.data[fieldName] = userText.trim()
    session.currentField++

    if (session.currentField < session.fields.length) {
      const nextField = session.fields[session.currentField]
      await sock.sendMessage(jid, { text: `Enter your ${nextField}:` })
      continue
    }

    // All fields collected — save
    saveAccount(session.platform, session.data)
    const label = platforms[session.platform].label
    onboardingSessions.delete(jid)
    await sock.sendMessage(jid, { text: `${label} account saved successfully.` })
    console.log(`[${jid}] onboard: ${label} configured`)
    continue
  }

  // Unknown state — reset
  onboardingSessions.delete(jid)
}

